                </button>
            </div>
        </div>;
}

@code {
    // ── Navigation ──
    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;

    private readonly Dictionary<string, (string Label, string Icon)> _sections = new()
    {
        ["profile"] = ("Profile", "👤"),
        ["notifications"] = ("Notifications", "🔔"),
        ["security"] = ("Security", "🛡️"),
        ["appearance"] = ("Appearance", "🎨"),
    };

    // ── Toast ──
    private bool _toastVisible;
    private string _toastMessage = "";
    private bool _toastIsError;
    private bool _saving;

    // ── Profile ──
    private string _profileDisplayName = "";
    private string _profileEmail = "";
    private string _profileAvatarUrl = "";
    private string _profileBio = "";
    private UserProfile? _savedProfile;

    // ── Notifications ──
    private bool _notifEmail;
    private bool _notifPush;
    private bool _notifDigest;
    private List<string> _allChannels = [];
    private HashSet<string> _mutedChannels = [];

    // ── Security ──
    private SecuritySettings? _securitySettings;
    private bool _twoFactorEnabled;
    private List<ActiveSession>? _sessions;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private ActiveSession? _sessionToRevoke;

    // ── Appearance ──
    private string _appTheme = "Light";
    private string _appFontSize = "Medium";
    private string _appLanguage = "English";
    private bool _appCompactMode;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllSettings();
        _loading = false;
    }

    private async Task LoadAllSettings()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var secTask = SettingsService.GetSecuritySettingsAsync();
        var appTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, secTask, appTask);

        var profile = profileTask.Result;
        _savedProfile = profile;
        _profileDisplayName = profile.DisplayName;
        _profileEmail = profile.Email;
        _profileAvatarUrl = profile.AvatarUrl;
        _profileBio = profile.Bio;

        var notif = notifTask.Result;
        _notifEmail = notif.EmailNotifications;
        _notifPush = notif.PushNotifications;
        _notifDigest = notif.WeeklyDigest;
        _allChannels = new List<string>(notif.MutedChannels);
        _mutedChannels = new HashSet<string>(notif.MutedChannels);

        _securitySettings = secTask.Result;
        _twoFactorEnabled = _securitySettings.TwoFactorEnabled;
        _sessions = new List<ActiveSession>(_securitySettings.Sessions);

        var appearance = appTask.Result;
        _appTheme = appearance.Theme;
        _appFontSize = appearance.FontSize;
        _appLanguage = appearance.Language;
        _appCompactMode = appearance.CompactMode;
    }

    private void SetActiveSection(string section)
    {
        ActiveSection = section;
    }

    // ── Toast helper ──
    private async Task ShowToast(string message, bool isError = false)
    {
        _toastMessage = message;
        _toastIsError = isError;
        _toastVisible = true;
        StateHasChanged();
        await Task.Delay(3000);
        _toastVisible = false;
        StateHasChanged();
    }

    // ── Profile ──
    private async Task SaveProfile()
    {
        _saving = true;
        var profile = new UserProfile(_profileDisplayName, _profileEmail, _profileAvatarUrl, _profileBio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        _saving = false;
        await ShowToast("Profile saved successfully!");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is null) return;
        _profileDisplayName = _savedProfile.DisplayName;
        _profileEmail = _savedProfile.Email;
        _profileAvatarUrl = _savedProfile.AvatarUrl;
        _profileBio = _savedProfile.Bio;
    }

    // ── Notifications ──
    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        var prefs = new NotificationPrefs(_notifEmail, _notifPush, _notifDigest, _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        await ShowToast("Notification preferences saved!");
    }

    // ── Security ──
    private async Task UpdatePassword()
    {
        _passwordError = null;
        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        _saving = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _passwordPanelOpen = false;
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        _saving = false;
        await ShowToast("Password updated successfully!");
    }

    private void PromptRevokeSession(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is null) return;
        _saving = true;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _sessions = _sessions?.Where(s => s.Id != _sessionToRevoke.Id).ToList();
        _sessionToRevoke = null;
        _saving = false;
        await ShowToast("Session revoked.");
    }

    // ── Appearance ──
    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(_appTheme.ToLowerInvariant() switch
        {
            "dark" => "preview-dark",
            "system" => "preview-system",
            _ => "preview-light"
        });
        classes.Add(_appFontSize.ToLowerInvariant() switch
        {
            "small" => "preview-font-small",
            "large" => "preview-font-large",
            _ => "preview-font-medium"
        });
        if (_appCompactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        var settings = new AppearanceSettings(_appTheme, _appFontSize, _appLanguage, _appCompactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _saving = false;
        await ShowToast("Appearance settings saved!");
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

