@* ── Security Section ── *@
@{
    RenderFragment RenderSecuritySection() =>
        @<div class="section-panel">
            <h2>Security</h2>
            <p class="section-description">Protect your account with passwords and session management.</p>

            <!-- Change Password -->
            <div class="expandable-panel">
                <button class="expandable-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <span>🔒 Change Password</span>
                    <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
                </button>
                @if (_passwordPanelOpen)
                {
                    <div class="expandable-body">
                        <div class="form-group">
                            <label for="currentPw">Current Password</label>
                            <input id="currentPw" type="password" class="form-control"
                                   @bind="_currentPassword" />
                        </div>
                        <div class="form-group">
                            <label for="newPw">New Password</label>
                            <input id="newPw" type="password" class="form-control"
                                   @bind="_newPassword" />
                        </div>
                        <div class="form-group">
                            <label for="confirmPw">Confirm Password</label>
                            <input id="confirmPw" type="password" class="form-control"
                                   @bind="_confirmPassword" />
                        </div>
                        @if (!string.IsNullOrEmpty(_passwordError))
                        {
                            <div class="alert alert-danger">@_passwordError</div>
                        }
                        <button class="btn btn-warning" @onclick="UpdatePassword" disabled="@_saving">
                            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Update Password
                        </button>
                    </div>
                }
            </div>

            <!-- Two-factor -->
            <div class="toggle-row mt-4">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <p class="text-muted mb-0">
                        Status:
                        <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </p>
                </div>
                <label class="toggle-switch">
                    <input type="checkbox" @bind="_twoFactorEnabled" />
                    <span class="toggle-slider"></span>
                </label>
            </div>

            @if (_securitySettings?.LastPasswordChange is not null)
            {
                <p class="text-muted mt-2">
                    Last password change: @_securitySettings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </p>
            }

            <!-- Active Sessions -->
            <h4 class="mt-4">Active Sessions</h4>
            <div class="table-responsive">
                <table class="table table-striped">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @if (_sessions is not null)
                        {
                            @foreach (var session in _sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (session.Id != _sessions.FirstOrDefault()?.Id)
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => PromptRevokeSession(session)">
                                                Revoke
                                            </button>
                                        }
                                        else
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                    </td>
                                </tr>
                            }
                        }
                    </tbody>
                </table>
            </div>

            <!-- Revoke confirmation dialog -->
            @if (_sessionToRevoke is not null)
            {
                <div class="modal-backdrop-custom">
                    <div class="confirmation-dialog">
                        <h5>Revoke Session</h5>
                        <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                        <div class="button-group">
                            <button class="btn btn-danger" @onclick="ConfirmRevokeSession" disabled="@_saving">
                                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                                Revoke
                            </button>
                            <button class="btn btn-outline-secondary" @onclick="() => _sessionToRevoke = null">
                                Cancel
                            </button>
                        </div>
                    </div>
                </div>
            }
        </div>;
}

@* ── Appearance Section ── *@
@{
    RenderFragment RenderAppearanceSection() =>
        @<div class="section-panel">
            <h2>Appearance</h2>
            <p class="section-description">Customize the look and feel of your application.</p>

            <div class="appearance-grid">
                <div class="appearance-controls">
                    <!-- Theme -->
                    <fieldset class="form-group">
                        <legend>Theme</legend>
                        @foreach (var theme in new[] { "Light", "Dark", "System" })
                        {
                            var t = theme;
