.sidebar-nav li {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.25rem;
    cursor: pointer;
    color: #6c757d;
    font-weight: 500;
    transition: background 0.15s, color 0.15s;
    border-left: 3px solid transparent;
}

.sidebar-nav li:hover {
    background: #f1f3f5;
    color: #212529;
}

.sidebar-nav li.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
}

.nav-icon {
    font-size: 1.15rem;
}

