toolArgs.file_text:
@page "/settings"
@using sv_53e5c34c73524b8c9222215553e63fab.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <!-- Left sidebar navigation -->
    <nav class="settings-sidebar">
        <h3 class="sidebar-title">Settings</h3>
        <ul class="sidebar-nav">
            @foreach (var section in _sections)
            {
                <li class="@(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => SetActiveSection(section.Key)">
                    <span class="nav-icon">@section.Value.Icon</span>
                    <span>@section.Value.Label</span>
                </li>
            }
        </ul>
    </nav>

    <!-- Main content area -->
    <div class="settings-content">
        @if (_loading)
        {
            <div class="loading-spinner">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }

        @if (_toastVisible)
        {
            <div class="toast-message @(_toastIsError ? "toast-error" : "toast-success")">
                @_toastMessage
            </div>
        }
    </div>
</div>

@* ── Profile Section ── *@
@{
    RenderFragment RenderProfileSection() =>
        @<div class="section-panel">
            <h2>Profile</h2>
            <p class="section-description">Manage your personal information and public profile.</p>

            <div class="avatar-area">
                <img src="@_profileDisplayName" alt="Avatar"
                     class="avatar-preview"
                     @onerror="((Action)(() => {}))"
                     style="display:none;" />
                <div class="avatar-placeholder">
                    <img src="@_profileAvatarUrl" alt="Avatar" class="avatar-preview" />
                </div>
                <div class="avatar-url-display">
                    <label>Avatar URL</label>
                    <span class="text-muted">@_profileAvatarUrl</span>
                </div>
            </div>

            <div class="form-group">
                <label for="displayName">Display Name</label>
                <input id="displayName" type="text" class="form-control"
                       @bind="_profileDisplayName" @bind:event="oninput" />
            </div>

            <div class="form-group">
                <label for="email">Email</label>
                <input id="email" type="email" class="form-control"
                       @bind="_profileEmail" @bind:event="oninput" />
            </div>

            <div class="form-group">
                <label for="bio">Bio</label>
                <textarea id="bio" class="form-control" rows="4"
                          @bind="_profileBio" @bind:event="oninput"></textarea>
            </div>

            <div class="button-group">
                <button class="btn btn-primary" @onclick="SaveProfile" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save Changes
                </button>
                <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">
                    Discard Changes
                </button>
            </div>
        </div>;
}

@* ── Notifications Section ── *@
@{
    RenderFragment RenderNotificationsSection() =>
        @<div class="section-panel">
            <h2>Notifications</h2>
            <p class="section-description">Choose how and when you want to be notified.</p>

            <div class="toggle-group">
                <div class="toggle-row">
                    <div>
                        <strong>Email Notifications</strong>
                        <p class="text-muted mb-0">Receive updates via email</p>
                    </div>
                    <label class="toggle-switch">
                        <input type="checkbox" @bind="_notifEmail" />
                        <span class="toggle-slider"></span>
                    </label>
                </div>

                <div class="toggle-row">
                    <div>
                        <strong>Push Notifications</strong>
                        <p class="text-muted mb-0">Browser and mobile push alerts</p>
                    </div>
                    <label class="toggle-switch">
                        <input type="checkbox" @bind="_notifPush" />
                        <span class="toggle-slider"></span>
                    </label>
                </div>

                <div class="toggle-row">
                    <div>
                        <strong>Weekly Digest</strong>
                        <p class="text-muted mb-0">Summary of activity every week</p>
                    </div>
                    <label class="toggle-switch">
                        <input type="checkbox" @bind="_notifDigest" />
                        <span class="toggle-slider"></span>
                    </label>
                </div>
            </div>

            <h4 class="mt-4">Muted Channels</h4>
            <p class="text-muted">Check channels you want to mute.</p>
            <div class="channel-list">
                @foreach (var channel in _allChannels)
                {
                    var ch = channel;
                    <label class="channel-item">
                        <input type="checkbox"
                               checked="@_mutedChannels.Contains(ch)"
                               @onchange="e => ToggleMutedChannel(ch, (bool)e.Value!)" />
                        <span>#@ch</span>
                    </label>
                }
            </div>

            <div class="button-group">
                <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save Preferences
                </button>
            </div>
        </div>;
}

@* ── Security Section ── *@
@{
    RenderFragment RenderSecuritySection() =>
        @<div class="section-panel">
            <h2>Security</h2>
            <p class="section-description">Protect your account with passwords and session management.</p>

            <!-- Change Password -->
            <div class="expandable-panel">
                <button class="expandable-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <span>🔒 Change Password</span>
                    <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
                </button>
                @if (_passwordPanelOpen)
                {
                    <div class="expandable-body">
                        <div class="form-group">
                            <label for="currentPw">Current Password</label>
                            <input id="currentPw" type="password" class="form-control"
                                   @bind="_currentPassword" />
                        </div>
                        <div class="form-group">
                            <label for="newPw">New Password</label>
                            <input id="newPw" type="password" class="form-control"
                                   @bind="_newPassword" />
                        </div>
                        <div class="form-group">
                            <label for="confirmPw">Confirm Password</label>
                            <input id="confirmPw" type="password" class="form-control"
                                   @bind="_confirmPassword" />
                        </div>
                        @if (!string.IsNullOrEmpty(_passwordError))
                        {
                            <div class="alert alert-danger">@_passwordError</div>
                        }
                        <button class="btn btn-warning" @onclick="UpdatePassword" disabled="@_saving">
                            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Update Password
                        </button>
                    </div>
                }
            </div>

            <!-- Two-factor -->
            <div class="toggle-row mt-4">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <p class="text-muted mb-0">
                        Status:
                        <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </p>
                </div>
                <label class="toggle-switch">
                    <input type="checkbox" @bind="_twoFactorEnabled" />
                    <span class="toggle-slider"></span>
                </label>
            </div>

            @if (_securitySettings?.LastPasswordChange is not null)
            {
                <p class="text-muted mt-2">
                    Last password change: @_securitySettings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </p>
            }

            <!-- Active Sessions -->
            <h4 class="mt-4">Active Sessions</h4>
            <div class="table-responsive">
                <table class="table table-striped">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @if (_sessions is not null)
                        {
                            @foreach (var session in _sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (session.Id != _sessions.FirstOrDefault()?.Id)
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => PromptRevokeSession(session)">
                                                Revoke
                                            </button>
                                        }
                                        else
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                    </td>
                                </tr>
                            }
                        }
                    </tbody>
                </table>
            </div>

            <!-- Revoke confirmation dialog -->
            @if (_sessionToRevoke is not null)
            {
                <div class="modal-backdrop-custom">
                    <div class="confirmation-dialog">
                        <h5>Revoke Session</h5>
                        <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                        <div class="button-group">
                            <button class="btn btn-danger" @onclick="ConfirmRevokeSession" disabled="@_saving">
                                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                                Revoke
                            </button>
                            <button class="btn btn-outline-secondary" @onclick="() => _sessionToRevoke = null">
                                Cancel
                            </button>
                        </div>
                    </div>
                </div>
            }
        </div>;
}

@* ── Appearance Section ── *@
@{
    RenderFragment RenderAppearanceSection() =>
        @<div class="section-panel">
            <h2>Appearance</h2>
            <p class="section-description">Customize the look and feel of your application.</p>

            <div class="appearance-grid">
                <div class="appearance-controls">
                    <!-- Theme -->
                    <fieldset class="form-group">
                        <legend>Theme</legend>
                        @foreach (var theme in new[] { "Light", "Dark", "System" })
                        {
                            var t = theme;
                            <label class="radio-option">
                                <input type="radio" name="theme" value="@t"
                                       checked="@(_appTheme == t)"
                                       @onchange="() => _appTheme = t" />
                                <span>@t</span>
                            </label>
                        }
                    </fieldset>

                    <!-- Font Size -->
                    <fieldset class="form-group">
                        <legend>Font Size</legend>
                        @foreach (var size in new[] { "Small", "Medium", "Large" })
                        {
                            var s = size;
                            <label class="radio-option">
                                <input type="radio" name="fontSize" value="@s"
                                       checked="@(_appFontSize == s)"
                                       @onchange="() => _appFontSize = s" />
                                <span>@s</span>
                            </label>
                        }
                    </fieldset>

                    <!-- Language -->
                    <div class="form-group">
                        <label for="language">Language</label>
                        <select id="language" class="form-select" @bind="_appLanguage">
                            <option value="English">English</option>
                            <option value="Spanish">Spanish</option>
                            <option value="French">French</option>
                            <option value="German">German</option>
                            <option value="Japanese">Japanese</option>
                            <option value="Chinese">Chinese</option>
                        </select>
                    </div>

                    <!-- Compact Mode -->
                    <div class="toggle-row">
                        <div>
                            <strong>Compact Mode</strong>
                            <p class="text-muted mb-0">Reduce spacing and padding</p>
                        </div>
                        <label class="toggle-switch">
                            <input type="checkbox" @bind="_appCompactMode" />
                            <span class="toggle-slider"></span>
                        </label>
                    </div>
                </div>

                <!-- Live Preview -->
                <div class="preview-area @GetPreviewClasses()">
                    <div class="preview-label">Live Preview</div>
                    <div class="preview-card">
                        <h5>Dashboard</h5>
                        <p>This is how your content will look with the current settings.</p>
                        <div class="preview-stats">
                            <div class="preview-stat">
                                <span class="stat-value">128</span>
                                <span class="stat-label">Messages</span>
                            </div>
                            <div class="preview-stat">
                                <span class="stat-value">42</span>
                                <span class="stat-label">Tasks</span>
                            </div>
                            <div class="preview-stat">
                                <span class="stat-value">7</span>
                                <span class="stat-label">Projects</span>
                            </div>
                        </div>
                        <button class="preview-btn">Sample Button</button>
                    </div>
                </div>
            </div>

            <div class="button-group">
                <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save
                </button>
            </div>
        </div>;
}

@code {
    // ── Navigation ──
    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;

    private readonly Dictionary<string, (string Label, string Icon)> _sections = new()
    {
        ["profile"] = ("Profile", "👤"),
        ["notifications"] = ("Notifications", "🔔"),
        ["security"] = ("Security", "🛡️"),
        ["appearance"] = ("Appearance", "🎨"),
    };

    // ── Toast ──
    private bool _toastVisible;
    private string _toastMessage = "";
    private bool _toastIsError;
    private bool _saving;

    // ── Profile ──
    private string _profileDisplayName = "";
    private string _profileEmail = "";
    private string _profileAvatarUrl = "";
    private string _profileBio = "";
    private UserProfile? _savedProfile;

    // ── Notifications ──
    private bool _notifEmail;
    private bool _notifPush;
    private bool _notifDigest;
    private List<string> _allChannels = [];
    private HashSet<string> _mutedChannels = [];

    // ── Security ──
    private SecuritySettings? _securitySettings;
    private bool _twoFactorEnabled;
    private List<ActiveSession>? _sessions;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private ActiveSession? _sessionToRevoke;

    // ── Appearance ──
    private string _appTheme = "Light";
    private string _appFontSize = "Medium";
    private string _appLanguage = "English";
    private bool _appCompactMode;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllSettings();
        _loading = false;
    }

    private async Task LoadAllSettings()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var secTask = SettingsService.GetSecuritySettingsAsync();
        var appTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, secTask, appTask);

        var profile = profileTask.Result;
        _savedProfile = profile;
        _profileDisplayName = profile.DisplayName;
        _profileEmail = profile.Email;
        _profileAvatarUrl = profile.AvatarUrl;
        _profileBio = profile.Bio;

        var notif = notifTask.Result;
        _notifEmail = notif.EmailNotifications;
        _notifPush = notif.PushNotifications;
        _notifDigest = notif.WeeklyDigest;
        _allChannels = new List<string>(notif.MutedChannels);
        _mutedChannels = new HashSet<string>(notif.MutedChannels);

        _securitySettings = secTask.Result;
        _twoFactorEnabled = _securitySettings.TwoFactorEnabled;
        _sessions = new List<ActiveSession>(_securitySettings.Sessions);

        var appearance = appTask.Result;
        _appTheme = appearance.Theme;
        _appFontSize = appearance.FontSize;
        _appLanguage = appearance.Language;
        _appCompactMode = appearance.CompactMode;
    }

    private void SetActiveSection(string section)
    {
        ActiveSection = section;
    }

    // ── Toast helper ──
    private async Task ShowToast(string message, bool isError = false)
    {
        _toastMessage = message;
        _toastIsError = isError;
        _toastVisible = true;
        StateHasChanged();
        await Task.Delay(3000);
        _toastVisible = false;
        StateHasChanged();
    }

    // ── Profile ──
    private async Task SaveProfile()
    {
        _saving = true;
        var profile = new UserProfile(_profileDisplayName, _profileEmail, _profileAvatarUrl, _profileBio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        _saving = false;
        await ShowToast("Profile saved successfully!");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is null) return;
        _profileDisplayName = _savedProfile.DisplayName;
        _profileEmail = _savedProfile.Email;
        _profileAvatarUrl = _savedProfile.AvatarUrl;
        _profileBio = _savedProfile.Bio;
    }

    // ── Notifications ──
    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        var prefs = new NotificationPrefs(_notifEmail, _notifPush, _notifDigest, _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        await ShowToast("Notification preferences saved!");
    }

    // ── Security ──
    private async Task UpdatePassword()
    {
        _passwordError = null;
        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        _saving = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _passwordPanelOpen = false;
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        _saving = false;
        await ShowToast("Password updated successfully!");
    }

    private void PromptRevokeSession(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is null) return;
        _saving = true;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _sessions = _sessions?.Where(s => s.Id != _sessionToRevoke.Id).ToList();
        _sessionToRevoke = null;
        _saving = false;
        await ShowToast("Session revoked.");
    }

    // ── Appearance ──
    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(_appTheme.ToLowerInvariant() switch
        {
            "dark" => "preview-dark",
            "system" => "preview-system",
            _ => "preview-light"
        });
        classes.Add(_appFontSize.ToLowerInvariant() switch
        {
            "small" => "preview-font-small",
            "large" => "preview-font-large",
            _ => "preview-font-medium"
        });
        if (_appCompactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        var settings = new AppearanceSettings(_appTheme, _appFontSize, _appLanguage, _appCompactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _saving = false;
        await ShowToast("Appearance settings saved!");
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

